import React from 'react';
import Logo from './Logo.png'; 
import Menu from './Menu'; 

function App() {
  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', margin: 0 }}>
      
      {/* THE FULL-SCREEN HEADER */}
      <header style={{ 
        width: '100vw', 
        height: '100vh',           // 1. Force it to take the ENTIRE screen height
        position: 'relative',
        overflow: 'hidden',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        backgroundColor: '#000'
      }}>
        
        <img 
          src={Logo} 
          alt="Àmí by T" 
          style={{ 
            width: '100%',         // 2. Force it to take the ENTIRE width
            height: '100%',        // 3. Force it to take the ENTIRE height
            objectFit: 'contain',  // 4. This "Crops" the view so it fills the space without stretching
            
            /* THE STAIN KILLER */
            /* Try 'screen' first. If the stain is WHITE, change 'screen' to 'multiply' */
            mixBlendMode: 'screen', 
            
            filter: 'contrast(1.2) brightness(1.1)', 
            padding: '40px'        // Gives the logo a little breathing room from the edges
          }} 
        />

        {/* Floating Tagline at the bottom of the header */}
        <div style={{ position: 'absolute', bottom: '10%' }}>
           <p style={{ color: '#D4AF37', letterSpacing: '8px', textTransform: 'uppercase' }}>
             Taste and Style
           </p>
        </div>
      </header>

      {/* THE MENU SECTION */}
      <main>
        <Menu />
      </main>

    </div>
  );
}

export default App;
